import {
  Box,
  Typography,
  Card,
  CardContent,
  Button,
  Chip,
  LinearProgress,
} from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';
import CheckCircleIcon from '@material-ui/icons/CheckCircle';
import RadioButtonUncheckedIcon from '@material-ui/icons/RadioButtonUnchecked';
import { Page, Header, Content } from '@backstage/core-components';
import { useNavigate } from 'react-router-dom';

const SUCCESS_COLOR_LIGHT = '#3E8635';
const SUCCESS_COLOR_DARK = '#8bc986';

const useStyles = makeStyles(theme => {
  const isDark = theme.palette.type === 'dark';
  const successColor = isDark ? SUCCESS_COLOR_DARK : SUCCESS_COLOR_LIGHT;

  return {
    section: {
      marginBottom: theme.spacing(4),
    },
    sectionTitle: {
      fontWeight: 600,
      marginBottom: theme.spacing(0.5),
    },
    sectionSubtitle: {
      color: theme.palette.text.secondary,
      marginBottom: theme.spacing(2),
    },

    card: {
      border: `1px solid ${theme.palette.divider}`,
      borderRadius: 8,
    },

    // Configuration progress
    progressHeader: {
      display: 'flex',
      alignItems: 'center',
      gap: theme.spacing(1),
      marginBottom: theme.spacing(1.5),
    },
    progressChip: {
      height: 22,
      fontSize: '0.75rem',
      fontWeight: 500,
      backgroundColor: isDark ? 'rgba(43, 154, 243, 0.15)' : 'rgba(43, 154, 243, 0.1)',
      color: isDark ? '#73BCF7' : '#0066CC',
    },
    progressBar: {
      height: 6,
      borderRadius: 3,
      marginBottom: theme.spacing(2.5),
      backgroundColor: isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.08)',
      '& .MuiLinearProgress-bar': {
        borderRadius: 3,
        backgroundColor: successColor,
      },
    },

    // Checklist
    checklistItem: {
      display: 'flex',
      alignItems: 'flex-start',
      gap: theme.spacing(1.5),
      padding: theme.spacing(1.5, 0),
      '&:not(:last-child)': {
        borderBottom: `1px solid ${theme.palette.divider}`,
      },
    },
    checkIcon: {
      fontSize: 20,
      marginTop: 1,
      color: successColor,
      flexShrink: 0,
    },
    pendingIcon: {
      fontSize: 20,
      marginTop: 1,
      color: theme.palette.text.disabled,
      flexShrink: 0,
    },
    checklistLabel: {
      fontSize: '0.875rem',
      fontWeight: 500,
    },
    checklistDone: {
      fontSize: '0.8125rem',
      color: successColor,
    },
    checklistPending: {
      fontSize: '0.8125rem',
      color: theme.palette.text.secondary,
    },

    // System info
    infoRow: {
      display: 'flex',
      alignItems: 'center',
      padding: theme.spacing(1.25, 0),
      '&:not(:last-child)': {
        borderBottom: `1px solid ${theme.palette.divider}`,
      },
    },
    infoLabel: {
      color: theme.palette.text.secondary,
      fontSize: '0.875rem',
      minWidth: 180,
      flexShrink: 0,
    },
    infoValue: {
      fontSize: '0.875rem',
      fontWeight: 500,
      fontFamily: 'monospace',
    },
  };
});

interface ChecklistEntry {
  label: string;
  done: boolean;
  detail: string;
}

const CHECKLIST: ChecklistEntry[] = [
  {
    label: 'Connect to Ansible Automation Platform',
    done: true,
    detail: 'Connected to aap.example.com',
  },
  {
    label: 'Select AAP organizations',
    done: true,
    detail: '3 organizations syncing',
  },
  {
    label: 'Connect source control',
    done: true,
    detail: 'GitHub connected',
  },
  {
    label: 'Configure quality scanning',
    done: false,
    detail:
      'Set up APME to scan content for compatibility and quality issues',
  },
];

const SYSTEM_INFO = [
  { label: 'Deployment mode', value: 'Local development' },
  { label: 'Portal version', value: '1.0.0-dev' },
  { label: 'Portal base URL', value: 'https://portal.example.com' },
];

export const GeneralPage = () => {
  const classes = useStyles();
  const navigate = useNavigate();

  const doneCount = CHECKLIST.filter(c => c.done).length;
  const totalCount = CHECKLIST.length;
  const progressPercent = (doneCount / totalCount) * 100;

  return (
    <Page themeId="tool">
      <Header
        title="General"
        subtitle="Portal configuration and deployment status"
      />
      <Content>
        {/* Complete your configuration */}
        <Box className={classes.section}>
          <Card className={classes.card} elevation={0}>
            <CardContent>
              <Box className={classes.progressHeader}>
                <Typography variant="subtitle1" style={{ fontWeight: 600 }}>
                  Complete your configuration
                </Typography>
                <Chip
                  label={`${doneCount} of ${totalCount}`}
                  size="small"
                  className={classes.progressChip}
                />
              </Box>

              <LinearProgress
                variant="determinate"
                value={progressPercent}
                className={classes.progressBar}
              />

              {CHECKLIST.map(item => (
                <Box key={item.label} className={classes.checklistItem}>
                  {item.done ? (
                    <CheckCircleIcon className={classes.checkIcon} />
                  ) : (
                    <RadioButtonUncheckedIcon
                      className={classes.pendingIcon}
                    />
                  )}
                  <Box flex={1}>
                    <Typography className={classes.checklistLabel}>
                      {item.label}
                    </Typography>
                    <Typography
                      className={
                        item.done
                          ? classes.checklistDone
                          : classes.checklistPending
                      }
                    >
                      {item.detail}
                    </Typography>
                  </Box>
                  {!item.done && (
                    <Button
                      variant="outlined"
                      color="primary"
                      size="small"
                      onClick={() =>
                        navigate('/self-service/admin/integrations')
                      }
                    >
                      Configure
                    </Button>
                  )}
                </Box>
              ))}
            </CardContent>
          </Card>
        </Box>

        {/* System information */}
        <Box className={classes.section}>
          <Typography variant="h6" className={classes.sectionTitle}>
            System information
          </Typography>
          <Typography variant="body2" className={classes.sectionSubtitle}>
            Read-only deployment details
          </Typography>
          <Card className={classes.card} elevation={0}>
            <CardContent>
              {SYSTEM_INFO.map(row => (
                <Box key={row.label} className={classes.infoRow}>
                  <Typography className={classes.infoLabel}>
                    {row.label}
                  </Typography>
                  <Typography className={classes.infoValue}>
                    {row.value}
                  </Typography>
                </Box>
              ))}
            </CardContent>
          </Card>
        </Box>
      </Content>
    </Page>
  );
};
